(function () {
  'use strict';
  var nav     = document.getElementById('ztNav');
  var burger  = document.getElementById('ztBurger');
  var overlay = document.getElementById('ztOverlay');
  var closeBtn= document.getElementById('ztClose');
  if (!nav || !overlay) return;

  /* ---- collapse on the FIRST scroll (rAF-throttled, reversible):
         contact slides left, burger slides in from the right, inline links
         (which scroll away on their own) also fade out. ---- */
  var inline = document.getElementById('ztInline');
  var ticking = false;
  function onScroll() {
    if (ticking) return;
    ticking = true;
    requestAnimationFrame(function () {
      var scrolled = window.scrollY > 24;
      nav.classList.toggle('is-scrolled', scrolled);
      if (inline) inline.classList.toggle('is-scrolled', scrolled);
      ticking = false;
    });
  }
  window.addEventListener('scroll', onScroll, { passive: true });
  onScroll();

  /* ---- fullscreen overlay: open/close + focus trap ---- */
  var lastFocus = null;
  function focusables() {
    return overlay.querySelectorAll('a[href], button:not([disabled])');
  }
  function openMenu() {
    lastFocus = document.activeElement;
    overlay.classList.add('is-open');
    overlay.setAttribute('aria-hidden', 'false');
    burger.setAttribute('aria-expanded', 'true');
    document.body.style.overflow = 'hidden';
    if (window.__lenis) window.__lenis.stop();
    var f = focusables();
    if (f.length) f[0].focus();
    document.addEventListener('keydown', onKey);
  }
  function closeMenu() {
    overlay.classList.remove('is-open');
    overlay.setAttribute('aria-hidden', 'true');
    burger.setAttribute('aria-expanded', 'false');
    document.body.style.overflow = '';
    if (window.__lenis) window.__lenis.start();
    document.removeEventListener('keydown', onKey);
    if (lastFocus && lastFocus.focus) lastFocus.focus();
  }
  function onKey(e) {
    if (e.key === 'Escape') { closeMenu(); return; }
    if (e.key === 'Tab') {
      var f = focusables(); if (!f.length) return;
      var first = f[0], last = f[f.length - 1];
      if (e.shiftKey && document.activeElement === first) { e.preventDefault(); last.focus(); }
      else if (!e.shiftKey && document.activeElement === last) { e.preventDefault(); first.focus(); }
    }
  }
  burger.addEventListener('click', openMenu);
  closeBtn.addEventListener('click', closeMenu);
  overlay.querySelectorAll('.zt-overlay-nav a').forEach(function (a) {
    a.addEventListener('click', closeMenu);
  });

  /* ---- language toggle (visual state only) ---- */
  overlay.querySelectorAll('.zt-lang button').forEach(function (b) {
    b.addEventListener('click', function () {
      overlay.querySelectorAll('.zt-lang button').forEach(function (x) {
        x.classList.remove('is-active'); x.setAttribute('aria-pressed', 'false');
      });
      b.classList.add('is-active'); b.setAttribute('aria-pressed', 'true');
    });
  });

  /* ---- smooth fade-in once the preloader hands off (fallback if missed) ---- */
  function revealNav() {
    nav.classList.remove('zt-prereveal');
    if (inline) inline.classList.remove('zt-prereveal');
  }
  document.addEventListener('oh:preloaded', revealNav);
  setTimeout(revealNav, 9000);
})();

(function () {
  'use strict';
  var reduce = window.matchMedia && window.matchMedia('(prefers-reduced-motion: reduce)').matches;

  /* --- split the big headline into words/chars (keeps wrapping) --- */
  var display = document.querySelector('[data-ohx-fill]');
  var fillChars = [];
  if (display) {
    var words = display.textContent.trim().split(/\s+/);
    display.textContent = '';
    words.forEach(function (w, wi) {
      var wEl = document.createElement('span');
      wEl.className = 'ohx-word';
      w.split('').forEach(function (ch) {
        var c = document.createElement('span');
        c.className = 'ohx-char';
        c.textContent = ch;
        wEl.appendChild(c);
        fillChars.push(c);
      });
      display.appendChild(wEl);
      if (wi < words.length - 1) display.appendChild(document.createTextNode(' '));
    });
    if (reduce) fillChars.forEach(function (c) { c.classList.add('is-lit'); });
  }

  /* --- split the lead paragraph into words for the reveal --- */
  var lead = document.querySelector('[data-ohx-words]');
  if (lead) {
    var lw = lead.textContent.trim().split(/\s+/);
    lead.textContent = '';
    lw.forEach(function (w, i) {
      var s = document.createElement('span');
      s.className = 'ohx-word';
      s.textContent = w;
      s.style.transitionDelay = (i * 0.022).toFixed(3) + 's';
      lead.appendChild(s);
      lead.appendChild(document.createTextNode(' '));
    });
  }

  /* --- reveal the STATIC left column (lead + link) on enter --- */
  if ('IntersectionObserver' in window) {
    var io = new IntersectionObserver(function (entries) {
      entries.forEach(function (e) {
        if (e.isIntersecting) { e.target.classList.add('is-in'); io.unobserve(e.target); }
      });
    }, { threshold: 0.25 });
    document.querySelectorAll('.ohx-grid-text').forEach(function (el) { io.observe(el); });
  } else {
    document.querySelectorAll('.ohx-grid-text').forEach(function (el) { el.classList.add('is-in'); });
  }

  /* --- two-column parallax + headline char-fill, in one gated rAF loop ---
     Columns translate vertically at different rates as the section travels
     through the viewport (progress 0 = top enters bottom of viewport,
     1 = bottom leaves top). Transform-only, never top/margin. */
  var grid = document.querySelector('.ohx-grid');
  var tb   = document.querySelector('.ohx-textblock');
  var colA = document.querySelector('.ohx-stats-col--a');
  var colB = document.querySelector('.ohx-stats-col--b');
  /* opposing-parallax travel (px peak-to-peak); scales down on narrower screens */
  function speeds() {
    var w = window.innerWidth;
    if (w < 600) return [70, 70];
    if (w < 1024) return [120, 120];
    return [170, 170];
  }

  function noParallax() { return reduce; }   /* runs on desktop AND mobile */
  function clearCols() { if (colA) colA.style.transform = ''; if (colB) colB.style.transform = ''; }
  function nearView(el, m) {
    var r = el.getBoundingClientRect();
    return r.bottom > -m && r.top < window.innerHeight + m;
  }

  var tbIn = false, grIn = false, looping = false;
  function tick() {
    if (!(tbIn || grIn)) { looping = false; return; }
    var vh = window.innerHeight;

    if (display && fillChars.length && !reduce && tbIn) {
      var dr = display.getBoundingClientRect();
      var p = (vh * 0.82 - dr.top) / (vh * 0.82 - vh * 0.3);
      p = Math.max(0, Math.min(1, p));
      var n = Math.round(p * fillChars.length);
      for (var i = 0; i < fillChars.length; i++) {
        var lit = i < n;
        if (fillChars[i].classList.contains('is-lit') !== lit) fillChars[i].classList.toggle('is-lit', lit);
      }
    }

    if (colA && colB && grIn && !noParallax()) {
      var gr = grid.getBoundingClientRect();
      var prog = (vh - gr.top) / (vh + gr.height);
      prog = Math.max(0, Math.min(1, prog));
      var sp = speeds();
      var d = prog - 0.5;                                                   /* centered on mid-scroll */
      colA.style.transform = 'translate3d(0,' + (d * sp[0]).toFixed(1) + 'px,0)';   /* left: up -> down */
      colB.style.transform = 'translate3d(0,' + (-d * sp[1]).toFixed(1) + 'px,0)';  /* right: down -> up */
    }
    requestAnimationFrame(tick);
  }
  function ensureLoop() { if (!looping && (tbIn || grIn)) { looping = true; requestAnimationFrame(tick); } }

  if ('IntersectionObserver' in window) {
    var io2 = new IntersectionObserver(function (entries) {
      entries.forEach(function (e) {
        if (e.target === tb) tbIn = e.isIntersecting;
        if (e.target === grid) {
          grIn = e.isIntersecting && !noParallax();
          if (noParallax()) clearCols();
        }
      });
      ensureLoop();
    }, { rootMargin: '300px 0px 300px 0px' });
    if (tb) io2.observe(tb);
    if (grid) io2.observe(grid);
  } else {
    tbIn = true; grIn = !noParallax(); ensureLoop();
  }

  window.addEventListener('resize', function () {
    if (noParallax()) { grIn = false; clearCols(); }
    else if (grid) { grIn = nearView(grid, 300); }
    if (tb) tbIn = nearView(tb, 300);
    ensureLoop();
  });
})();

(function(){
  if (window.__ohprInit) return; window.__ohprInit = true;
  function boot(){
    var sec = document.getElementById('ohProjects');
    if (!sec || sec.__booted) return; sec.__booted = true;
    var grid = sec.classList.contains('ohpr--grid');
    var vp = sec.querySelector('[data-ohpr-viewport]');
    var track = sec.querySelector('[data-ohpr-track]');
    var cards = Array.prototype.slice.call(track.querySelectorAll('.ohpr-card'));
    var prog = sec.querySelector('[data-ohpr-prog]');
    var curEl = sec.querySelector('[data-ohpr-cur]');
    var totEl = sec.querySelector('[data-ohpr-total]');
    var prev = sec.querySelector('[data-ohpr-prev]');
    var next = sec.querySelector('[data-ohpr-next]');
    var tabs = Array.prototype.slice.call(sec.querySelectorAll('.ohpr-tab'));

    function pad(n){ return (n<10?'0':'')+n; }
    function step(){
      var c = cards.find(function(x){ return !x.classList.contains('is-hidden'); });
      if (!c) return 1;
      var gap = parseFloat(getComputedStyle(track).columnGap || getComputedStyle(track).gap || 0) || 0;
      return c.getBoundingClientRect().width + gap;
    }
    function visible(){ return cards.filter(function(x){ return !x.classList.contains('is-hidden'); }); }

    function update(){
      if (grid) return;
      var max = vp.scrollWidth - vp.clientWidth;
      var p = max > 2 ? vp.scrollLeft / max : 0;
      prog.style.width = Math.max(0, Math.min(1, p)) * 100 + '%';
      var tot = visible().length;
      var idx = Math.round(vp.scrollLeft / step()) + 1;
      idx = Math.max(1, Math.min(tot, idx));
      curEl.textContent = pad(idx); totEl.textContent = pad(tot);
      var atStart = vp.scrollLeft <= 2, atEnd = vp.scrollLeft >= max - 2 || max <= 2;
      prev.disabled = atStart; next.disabled = atEnd;
    }
    function go(dir){ vp.scrollBy({ left: dir * step(), behavior: 'smooth' }); }

    if (!grid){
      prev.addEventListener('click', function(){ go(-1); });
      next.addEventListener('click', function(){ go(1); });
      vp.addEventListener('scroll', function(){ window.requestAnimationFrame(update); });
      window.addEventListener('resize', update);
    }

    tabs.forEach(function(t){
      t.addEventListener('click', function(){
        tabs.forEach(function(x){ x.classList.remove('is-active'); });
        t.classList.add('is-active');
        var f = t.getAttribute('data-filter');
        cards.forEach(function(c){
          var show = (f === 'all') || (c.getAttribute('data-region') === f);
          c.classList.toggle('is-hidden', !show);
          if (!show) c.classList.remove('is-open');
        });
        vp.scrollTo({ left: 0, behavior: 'auto' });
        update();
      });
    });

    /* expandable quick-preview */
    cards.forEach(function(c){
      var openBtn = c.querySelector('[data-ohpr-open]');
      var closeBtn = c.querySelector('[data-ohpr-close]');
      if (openBtn) openBtn.addEventListener('click', function(e){ e.preventDefault(); c.classList.add('is-open'); });
      if (closeBtn) closeBtn.addEventListener('click', function(e){ e.preventDefault(); c.classList.remove('is-open'); });
    });

    update();
    if (document.fonts && document.fonts.ready) document.fonts.ready.then(update);
    setTimeout(update, 500);
  }
  if (document.readyState !== 'loading') boot();
  else document.addEventListener('DOMContentLoaded', boot);
  document.addEventListener('oh:preloaded', boot);
})();

(function () {
  'use strict';

  if ('scrollRestoration' in history) history.scrollRestoration = 'manual';
  window.scrollTo(0, 0);
  document.body.classList.add('oh-preloader-active');

  function initOHPreloader() {
    var textEl  = document.getElementById('ohPreloaderText');
    var rawText = textEl.textContent.trim();
    var words   = rawText.split(/\s+/);

    var staggerTime     = 0.05;
    var charDuration    = 0.5;
    var startDelay      = 0.3;
    var splitDelay      = 0.6;
    var splitDuration   = 1.0;
    var expandDuration  = 1.0;
    var textGap         = 30;

    textEl.innerHTML = '';
    var wordElements = [];

    words.forEach(function (word, wordIndex) {
      var wordWrapper = document.createElement('span');
      wordWrapper.className = 'oh-preloader__word';

      word.split('').forEach(function (ch) {
        var cw = document.createElement('span');
        cw.className = 'oh-preloader__char-wrapper';

        var cs = document.createElement('span');
        cs.className = 'oh-preloader__char';
        cs.setAttribute('data-oh-word', wordIndex);
        cs.textContent = ch;

        cw.appendChild(cs);
        wordWrapper.appendChild(cw);
      });

      textEl.appendChild(wordWrapper);
      wordElements.push(wordWrapper);

      if (wordIndex < words.length - 1) {
        var space = document.createElement('span');
        space.className = 'oh-preloader__word-space';
        textEl.appendChild(space);
      }
    });

    var revealMedia = document.getElementById('ohRevealMedia');
    var video       = revealMedia.querySelector('video');
    var preloader   = document.getElementById('ohPreloader');

    function runAnimation() {
      textEl.parentElement.style.visibility = 'visible';

      var textRect   = textEl.getBoundingClientRect();
      var textHeight = textRect.height;

      var aspectRatio = video.videoWidth / video.videoHeight;
      var mediaWidth  = textHeight * aspectRatio;
      var halfMedia   = mediaWidth / 2 + textGap;

      var spaces = document.querySelectorAll('.oh-preloader__word-space');
      var slotSpace = spaces[0];
      var slotRect  = slotSpace.getBoundingClientRect();
      var slotCenterX = slotRect.left + slotRect.width / 2;

      gsap.set(revealMedia, {
        width:    mediaWidth,
        height:   textHeight,
        left:     slotCenterX - mediaWidth / 2,
        top:      textRect.top,
        clipPath: 'inset(0 50% 0 50%)'
      });

      var tl = gsap.timeline();

      words.forEach(function (_w, i) {
        var chars = document.querySelectorAll('.oh-preloader__char[data-oh-word="' + i + '"]');
        tl.to(chars, {
          y: '0%',
          duration: charDuration,
          ease: 'power3.out',
          stagger: staggerTime
        }, startDelay);
      });

      tl.to(revealMedia, {
        opacity: 1,
        duration: splitDuration * 0.35,
        ease: 'power2.out'
      }, '>+' + splitDelay);

      tl.fromTo(revealMedia,
        { clipPath: 'inset(0 50% 0 50%)' },
        { clipPath: 'inset(0 0% 0 0%)', duration: splitDuration, ease: 'power4.inOut' },
        '<'
      );

      tl.to(wordElements[0], { x: -halfMedia, duration: splitDuration, ease: 'power4.inOut' }, '<');

      if (wordElements.length >= 2)
        tl.to(wordElements[1], { x: halfMedia, duration: splitDuration, ease: 'power4.inOut' }, '<');

      if (wordElements.length >= 3)
        tl.to(wordElements[2], { x: halfMedia, duration: splitDuration, ease: 'power4.inOut' }, '<');

      tl.to(slotSpace, { width: 0, duration: splitDuration, ease: 'power4.inOut' }, '<');

      tl.to(revealMedia, {
        top: '87px',
        left: '2.5vh',
        width: 'calc(100vw - 5vh)',
        height: (window.innerHeight - 107) + 'px',
        borderRadius: '15px',
        duration: expandDuration,
        ease: 'power3.inOut'
      }, '>+=0.3');

      tl.call(function () {
        var videoBg = document.createElement('div');
        videoBg.className = 'oh-video-bg';
        videoBg.appendChild(video);
        document.body.insertBefore(videoBg, document.body.firstChild);

        preloader.remove();
        document.body.classList.remove('oh-preloader-active');
        document.body.style.overflow = '';
        document.dispatchEvent(new Event('oh:preloaded'));

        var heroElements = document.querySelectorAll('.oh-reveal .elementor-widget, .oh-reveal > *');
        if (heroElements.length) {
          gsap.to(heroElements, {
            opacity: 1,
            y: 0,
            duration: 0.8,
            ease: 'power3.out',
            stagger: 0.12,
            delay: 0.15
          });
        }
      });
    }

    function waitForVideo(cb) {
      if (video.readyState >= 1) cb();
      else video.addEventListener('loadeddata', cb, { once: true });
    }

    document.fonts.ready.then(function () {
      waitForVideo(runAnimation);
    });
  }

  if (document.readyState === 'loading')
    document.addEventListener('DOMContentLoaded', initOHPreloader);
  else
    initOHPreloader();

})();

/* Stylized property-finder dropdowns: progressively enhance each native <select>
   into a custom listbox (opens upward), keeping the real <select> for form submit
   and as a no-JS fallback. */
(function () {
  'use strict';
  var CARET = '<svg class="ohs-select-caret" viewBox="0 0 10 6" fill="none" aria-hidden="true">'
    + '<path d="M1 1l4 4 4-4" stroke="currentColor" stroke-width="1.3"/></svg>';

  function closeAll(except) {
    var open = document.querySelectorAll('.ohs-select.open');
    for (var i = 0; i < open.length; i++) {
      if (open[i] !== except && open[i]._close) open[i]._close();
    }
  }

  function enhance(field) {
    var sel = field.querySelector('select');
    if (!sel || field.classList.contains('ohs-enhanced')) return;
    field.classList.add('ohs-enhanced');

    var wrap = document.createElement('div');
    wrap.className = 'ohs-select';
    var trigger = document.createElement('button');
    trigger.type = 'button';
    trigger.className = 'ohs-select-trigger';
    trigger.setAttribute('aria-haspopup', 'listbox');
    trigger.setAttribute('aria-expanded', 'false');
    var label = field.querySelector('label');
    if (label) { if (!label.id) label.id = sel.id + '-lbl'; trigger.setAttribute('aria-labelledby', label.id); }
    trigger.innerHTML = '<span class="ohs-select-value"></span>' + CARET;

    var list = document.createElement('ul');
    list.className = 'ohs-select-list';
    list.setAttribute('role', 'listbox');
    if (label && label.id) list.setAttribute('aria-labelledby', label.id);

    var opts = Array.prototype.slice.call(sel.options);
    opts.forEach(function (o) {
      var li = document.createElement('li');
      li.className = 'ohs-select-opt';
      li.setAttribute('role', 'option');
      li.setAttribute('data-value', o.value);
      li.textContent = o.textContent;
      list.appendChild(li);
    });

    wrap.appendChild(trigger);
    wrap.appendChild(list);
    sel.parentNode.insertBefore(wrap, sel.nextSibling);

    var valueEl = trigger.querySelector('.ohs-select-value');
    var items = Array.prototype.slice.call(list.children);
    var activeIdx = Math.max(0, sel.selectedIndex);

    function paint() {
      var o = sel.options[sel.selectedIndex] || sel.options[0];
      valueEl.textContent = o ? o.textContent : '';
      valueEl.classList.toggle('is-placeholder', !sel.value);
      items.forEach(function (li, i) {
        if (i === sel.selectedIndex) li.setAttribute('aria-selected', 'true');
        else li.removeAttribute('aria-selected');
        li.classList.toggle('is-active', i === activeIdx);
      });
    }
    function choose(i) {
      sel.selectedIndex = i; activeIdx = i;
      try { sel.dispatchEvent(new Event('change', { bubbles: true })); } catch (e) {}
      paint();
    }
    function setActive(i) {
      activeIdx = Math.max(0, Math.min(items.length - 1, i));
      items.forEach(function (li, n) { li.classList.toggle('is-active', n === activeIdx); });
      var li = items[activeIdx];
      if (li) li.scrollIntoView({ block: 'nearest' });
    }
    function open() { closeAll(wrap); wrap.classList.add('open'); trigger.setAttribute('aria-expanded', 'true'); setActive(sel.selectedIndex < 0 ? 0 : sel.selectedIndex); }
    function close() { wrap.classList.remove('open'); trigger.setAttribute('aria-expanded', 'false'); }
    wrap._close = close;

    trigger.addEventListener('click', function (e) {
      e.stopPropagation();
      wrap.classList.contains('open') ? close() : open();
    });
    list.addEventListener('click', function (e) {
      var li = e.target.closest ? e.target.closest('.ohs-select-opt') : null;
      if (!li) return;
      choose(items.indexOf(li)); close(); trigger.focus();
    });
    trigger.addEventListener('keydown', function (e) {
      var openNow = wrap.classList.contains('open');
      if (e.key === 'ArrowDown' || e.key === 'ArrowUp') {
        e.preventDefault();
        if (!openNow) { open(); return; }
        setActive(activeIdx + (e.key === 'ArrowDown' ? 1 : -1));
      } else if (e.key === 'Enter' || e.key === ' ') {
        e.preventDefault();
        if (openNow) { choose(activeIdx); close(); } else { open(); }
      } else if (e.key === 'Escape') {
        if (openNow) { e.preventDefault(); close(); }
      } else if (e.key === 'Tab') {
        close();
      }
    });

    paint();
  }

  function build() {
    var fields = document.querySelectorAll('.ohs-finder .ohs-field');
    for (var i = 0; i < fields.length; i++) enhance(fields[i]);
  }

  document.addEventListener('click', function () { closeAll(null); });
  if (document.readyState !== 'loading') build();
  else document.addEventListener('DOMContentLoaded', build);
  document.addEventListener('oh:preloaded', build);
})();

(function () {
  'use strict';

  var SLIDES = [
    {
      type: 'video',
      eyebrow: 'Darak Group',
      lines: ['Timeless homes,', 'thoughtfully crafted'],
      meta: 'Cairo · Egypt'
    },
    {
      type: 'image',
      src: '/wp-content/uploads/2026/02/1716-S.-New Cairo-Drive1.jpg',
      eyebrow: 'Featured Project',
      lines: ['Where the city', 'meets the bay'],
      meta: 'The Address New Cairo · New Cairo'
    },
    {
      type: 'image',
      src: '/wp-content/uploads/2026/02/1710-S.-New Cairo-Drive3-scaled.jpg',
      eyebrow: 'Featured Project',
      lines: ['Designed around', 'how you live'],
      meta: 'Zayed Dunes · New Cairo'
    },
    {
      type: 'image',
      src: '/wp-content/uploads/2026/02/4489-N-Michigan-Ave_1OAKStudios048-scaled.jpg',
      eyebrow: 'Featured Project',
      lines: ['Light, water &', 'modern living'],
      meta: '4489 N. Michigan Ave · New Cairo'
    }
  ];

  var AUTOPLAY = 7;          /* seconds per slide */
  var current = 0;
  var animating = false;
  var initialized = false;
  var slideEls = [];
  var progressTween = null;

  var rvEls, eyebrowEl, line1El, line2El, metaEl, curEl, barEl;

  function pad(n) { return (n + 1 < 10 ? '0' : '') + (n + 1); }

  function setCaption(i) {
    var s = SLIDES[i];
    eyebrowEl.textContent = s.eyebrow;
    line1El.textContent = s.lines[0];
    line2El.textContent = s.lines[1];
    metaEl.textContent = s.meta;
  }

  function revealCaption() {
    return gsap.to(rvEls, {
      y: '0%',
      duration: 0.9,
      ease: 'power3.out',
      stagger: 0.1
    });
  }

  function hideCaption() {
    return gsap.to(rvEls, {
      y: '-115%',
      duration: 0.45,
      ease: 'power2.in',
      stagger: 0.05
    });
  }

  function startProgress() {
    if (progressTween) progressTween.kill();
    progressTween = gsap.fromTo(barEl,
      { scaleX: 0 },
      {
        scaleX: 1,
        duration: AUTOPLAY,
        ease: 'none',
        onComplete: function () { go(current + 1); }
      }
    );
  }

  function go(n) {
    if (animating) return;
    animating = true;
    if (progressTween) progressTween.kill();
    gsap.set(barEl, { scaleX: 0 });

    var next = (n + SLIDES.length) % SLIDES.length;
    var outgoing = slideEls[current];
    var incoming = slideEls[next];

    gsap.set(incoming, { zIndex: 2, opacity: 0, scale: 1.06 });
    gsap.set(outgoing, { zIndex: 1 });

    gsap.to(incoming, {
      opacity: 1,
      scale: 1,
      duration: 1.2,
      ease: 'power2.inOut',
      onComplete: function () {
        outgoing.classList.remove('is-active');
        incoming.classList.add('is-active');
        gsap.set(outgoing, { clearProps: 'zIndex,opacity,scale' });
        gsap.set(incoming, { clearProps: 'zIndex,scale' });
      }
    });

    hideCaption().then(function () {
      setCaption(next);
      gsap.set(rvEls, { y: '115%' });
      revealCaption();
    });

    gsap.to(curEl, {
      opacity: 0,
      duration: 0.25,
      onComplete: function () {
        curEl.textContent = pad(next);
        gsap.to(curEl, { opacity: 1, duration: 0.25 });
      }
    });

    gsap.delayedCall(1.25, function () {
      current = next;
      animating = false;
      startProgress();
    });
  }

  function init() {
    if (initialized) return;
    var videoBg = document.querySelector('.oh-video-bg');
    if (!videoBg || !window.gsap) return;
    initialized = true;

    var video = videoBg.querySelector('video');

    SLIDES.forEach(function (s, i) {
      var d = document.createElement('div');
      d.className = 'ohs-slide' + (i === 0 ? ' is-active' : '');
      if (s.type === 'video' && video) {
        d.appendChild(video);
      } else {
        var img = document.createElement('img');
        img.src = s.src;
        img.alt = '';
        img.decoding = 'async';
        d.appendChild(img);
      }
      videoBg.appendChild(d);
      slideEls.push(d);
    });

    var ui = document.getElementById('ohsUI');
    document.body.appendChild(ui);
    ui.hidden = false;

    eyebrowEl = document.getElementById('ohsEyebrow');
    line1El   = document.getElementById('ohsLine1');
    line2El   = document.getElementById('ohsLine2');
    metaEl    = document.getElementById('ohsMeta');
    curEl     = document.getElementById('ohsCur');
    barEl     = document.getElementById('ohsBar');
    rvEls     = ui.querySelectorAll('.ohs-caption .ohs-rv');

    document.getElementById('ohsTotal').textContent = pad(SLIDES.length - 1);
    setCaption(0);

    document.getElementById('ohsPrev').addEventListener('click', function () { go(current - 1); });
    document.getElementById('ohsNext').addEventListener('click', function () { go(current + 1); });

    gsap.delayedCall(0.5, function () {
      revealCaption();
      startProgress();
    });
    gsap.fromTo('.ohs-finder',
      { y: 30, opacity: 0 },
      { y: 0, opacity: 1, duration: 0.9, ease: 'power3.out', delay: 0.8 }
    );
    gsap.to('.ohs-nav', { opacity: 1, duration: 0.9, delay: 1.0 });
  }

  document.addEventListener('oh:preloaded', init);

  /* Fallback in case the handoff event was missed */
  var poll = setInterval(function () {
    if (initialized) { clearInterval(poll); return; }
    if (document.querySelector('.oh-video-bg')) { init(); clearInterval(poll); }
  }, 1000);
  setTimeout(function () { clearInterval(poll); }, 30000);
})();

(function () {
  var track = document.getElementById('ohnTrack');
  if (!track || track.dataset.ohnInit) return;
  track.dataset.ohnInit = '1';
  var cards = track.querySelectorAll('.ohn-card');
  var sec = track.closest('#news');
  var prev = sec.querySelector('.ohn-prev'), next = sec.querySelector('.ohn-next');
  var dotsWrap = sec.querySelector('#ohnDots');
  function step() {
    if (cards.length < 2) return track.clientWidth;
    return cards[1].getBoundingClientRect().left - cards[0].getBoundingClientRect().left;
  }
  // dots (one per card)
  var dots = [];
  cards.forEach(function (c, i) {
    var li = document.createElement('li');
    li.addEventListener('click', function () { track.scrollTo({ left: i * step(), behavior: 'smooth' }); });
    dotsWrap.appendChild(li); dots.push(li);
  });
  function update() {
    var max = track.scrollWidth - track.clientWidth - 2;
    if (prev) prev.disabled = track.scrollLeft <= 2;
    if (next) next.disabled = track.scrollLeft >= max;
    var idx = Math.round(track.scrollLeft / step());
    dots.forEach(function (d, i) { d.classList.toggle('is-on', i === idx); });
  }
  if (prev) prev.addEventListener('click', function () { track.scrollBy({ left: -step(), behavior: 'smooth' }); });
  if (next) next.addEventListener('click', function () { track.scrollBy({ left: step(), behavior: 'smooth' }); });
  track.addEventListener('scroll', update, { passive: true });
  window.addEventListener('resize', update);
  // drag to scroll
  var down = false, startX = 0, startL = 0, moved = 0;
  track.addEventListener('pointerdown', function (e) {
    down = true; moved = 0; startX = e.clientX; startL = track.scrollLeft;
    track.classList.add('is-drag');
  });
  track.addEventListener('pointermove', function (e) {
    if (!down) return;
    var dx = e.clientX - startX; moved = Math.abs(dx);
    track.scrollLeft = startL - dx;
  });
  function end() { if (!down) return; down = false; track.classList.remove('is-drag'); }
  track.addEventListener('pointerup', end);
  track.addEventListener('pointercancel', end);
  track.addEventListener('pointerleave', end);
  // suppress click after a real drag
  cards.forEach(function (c) {
    c.addEventListener('click', function (e) { if (moved > 8) { e.preventDefault(); } });
  });
  update();
})();

const lazyloadRunObserver = () => {
	const lazyloadBackgrounds = document.querySelectorAll( `.e-con.e-parent:not(.e-lazyloaded)` );
	const lazyloadBackgroundObserver = new IntersectionObserver( ( entries ) => {
		entries.forEach( ( entry ) => {
			if ( entry.isIntersecting ) {
				let lazyloadBackground = entry.target;
				if( lazyloadBackground ) {
					lazyloadBackground.classList.add( 'e-lazyloaded' );
				}
				lazyloadBackgroundObserver.unobserve( entry.target );
			}
		});
	}, { rootMargin: '200px 0px 200px 0px' } );
	lazyloadBackgrounds.forEach( ( lazyloadBackground ) => {
		lazyloadBackgroundObserver.observe( lazyloadBackground );
	} );
};
const events = [
	'DOMContentLoaded',
	'elementor/lazyload/observe',
];
events.forEach( ( event ) => {
	document.addEventListener( event, lazyloadRunObserver );
} );

/* JPTV Texto Rodante GSAP scripts: */ 

(function() {
    var triggerType = "hover"; 

    if (triggerType === 'scroll' && typeof ScrollTrigger !== 'undefined') {
        gsap.registerPlugin(ScrollTrigger);
    }

    var wrapper = document.getElementById("trg_wrapper-uc_jptv_texto_rodante_gsap_elementor_3ed502d");
    if (!wrapper) return;

    var textMask = wrapper.querySelector('.trg-text-mask');
    var anchor = wrapper.querySelector('.trg-anchor'); 
    var lineEl = wrapper.querySelector('.trg-line');

    var duration = parseFloat("0.5") || 0.5;
    // NUEVO: Capturamos el Stagger (Si el usuario lo deja vacío o 0, es bloque sólido)
    var staggerVal = parseFloat("0") || 0;

    // --- FUNCIÓN SPLIT TEXT ---
    function splitText(el) {
        var text = el.innerText.trim(); 
        el.innerHTML = ''; 

        text.split('').forEach(function(char) {
            var charContent = char === ' ' ? '&nbsp;' : char;
            var spanWrapper = document.createElement('span');
            spanWrapper.classList.add('trg-char-wrapper');
            var original = document.createElement('span');
            original.classList.add('trg-char');
            original.innerHTML = charContent;
            var clone = document.createElement('span');
            clone.classList.add('trg-char', 'clone');
            clone.innerHTML = charContent;
            spanWrapper.appendChild(original);
            spanWrapper.appendChild(clone);
            el.appendChild(spanWrapper);
        });
    }

    if (textMask && anchor) {
        splitText(textMask);
        var originalChars = textMask.querySelectorAll('.trg-char:not(.clone)');
        var cloneChars = textMask.querySelectorAll('.trg-char.clone');

        // Configuración inicial
        gsap.set(cloneChars, { yPercent: 120 });

        // --- TIMELINE TEXTO ---
        var tlConfig = { paused: true }; 
        if (triggerType === 'scroll') {
            tlConfig.scrollTrigger = {
                trigger: anchor,
                start: "top center",
                end: "bottom top",
                toggleActions: "play none none reverse"
            };
            tlConfig.paused = false; 
        }

        var tl = gsap.timeline(tlConfig);

        // Animación usando la variable 'staggerVal'
        tl.to(originalChars, {
            yPercent: -120, 
            duration: duration,
            ease: "power3.out",
            stagger: staggerVal 
        }, 0);

        tl.to(cloneChars, {
            yPercent: 0,
            duration: duration,
            ease: "power3.out",
            stagger: staggerVal 
        }, 0);

        // --- EVENTOS HOVER ---
        if (triggerType === 'hover') {

            anchor.addEventListener('mouseenter', function() {
                tl.play();

                // Entrada Línea: Crece desde Izquierda
                if(lineEl) {
                    gsap.fromTo(lineEl, 
                        { transformOrigin: "left center", scaleX: 0 }, 
                        { scaleX: 1, duration: 0.4, ease: "power2.out", overwrite: true }
                    );
                }
            });

            anchor.addEventListener('mouseleave', function() {
                tl.reverse();

                // Salida Línea: Se va hacia la Derecha
                if(lineEl) {
                    gsap.to(lineEl, { 
                        transformOrigin: "right center", 
                        scaleX: 0, 
                        duration: 0.6, // Un poco más lento para que se aprecie la salida
                        ease: "power2.inOut", 
                        overwrite: true 
                    });
                }
            });
        }
    }
})();

